import fs from "fs";
import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";

export const config = {
  api: { bodyParser: false },
};

// Function to extract marks from scanned text
function extractMarks(text: string) {
  const marksPattern = /(\d+)\s+(\d+)/g;
// const marksPattern = /([A-Z\s]+)\s+(\d{2,3})/g;




let match;
let totalObtained = 0;
let marksArray = [];

while ((match = marksPattern.exec(text)) !== null) {
  let subject = match[1].trim();
  let obtainedMarks = parseInt(match[2], 10);
  marksArray.push({ subject, obtainedMarks });
  totalObtained += obtainedMarks;
}

console.log("Extracted Marks:", marksArray);
console.log("Total Marks:", totalObtained);

  return {
    percentage: (totalObtained / 500) * 100,
    totalObtained,
    marksArray,
  };
}

// Function to process a file and extract marks
async function processFile(filePath: string) {
  try {
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: process.env.OCR_API_KEY,
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
    });

    const result = await ocrResponse.json();

    if (!result || !result.ParsedResults) {
      return { error: "OCR API failed", percentage: 0 };
    }

    const extractedText = result.ParsedResults[0]?.ParsedText || "";
    return extractMarks(extractedText);
  } catch (error) {
    console.error("Error processing file:", error);
    return { error: "Error processing file", percentage: 0 };
  }
}

// API to check eligibility
export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json();

    const [user] = await db.query("SELECT * FROM users WHERE email = ?", [
      email,
    ]);

    if (!user.length) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const filePath1 = `./public${user[0].tenth_certificate}`;
    const filePath2 = `./public${user[0].twelfth_certificate}`;

    // Process both certificates
    const result1 = await processFile(filePath1);
    const result2 = await processFile(filePath2);

    // Determine eligibility
    const isEligible = result1.percentage >= 60 && result2.percentage >= 60;

    return NextResponse.json(
      {
        tenth_certificate: result1,
        twelfth_certificate: result2,
        eligible: isEligible
          ? "Yes, you are eligible!"
          : "Sorry, you are not eligible.",
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing files:", error);
    return NextResponse.json(
      { error: "Error processing files" },
      { status: 500 }
    );
  }
}
